#!/usr/bin/env python3
from pathlib import Path
import base64
import re
import shutil
import subprocess
import tempfile

MAIN = Path("lib/main.dart")
PUBSPEC = Path("pubspec.yaml")
BOOST = Path("lib/gameplay_boost.dart")
TARGET = Path("lib/quick_modes.dart")
SOURCE_B64 = """"""


def run(command):
    print("$ " + " ".join(command))
    subprocess.run(command, check=True)


for path in [MAIN, PUBSPEC, BOOST]:
    if not path.exists():
        raise SystemExit(
            f"Gerekli dosya bulunamadı: {path}\n"
            "Kurulumu BilgiRotasi deposunun ana klasöründe çalıştır."
        )

branch = subprocess.check_output(
    ["git", "branch", "--show-current"],
    text=True,
).strip()

if branch != "main":
    raise SystemExit(
        "Bu geliştirme yalnızca main dalına kurulabilir.\n"
        f"Şu anki dal: {branch or '(belirsiz)'}\n"
        "Önce: git switch main"
    )

main = MAIN.read_text(encoding="utf-8")
pubspec = PUBSPEC.read_text(encoding="utf-8")
boost = BOOST.read_text(encoding="utf-8")

if "part 'quick_modes.dart';" in main or TARGET.exists():
    raise SystemExit("Yeni oyun modları zaten kurulmuş görünüyor.")

for marker in [
    "part 'gameplay_boost.dart';",
    "const GameplayBoostSettingsButton(),",
    "FutureBuilder<SavedGame?>(",
    "Bilgi Rotası • Sürüm 1.22",
]:
    if marker not in main:
        raise SystemExit(f"Beklenen main.dart bölümü bulunamadı: {marker}")

for marker in [
    "class JokerWallet",
    "class GameplayBoostDialogs",
    "class XpGainResult",
    "class XpCelebration",
]:
    if marker not in boost:
        raise SystemExit(
            f"Beklenen gameplay_boost.dart bölümü bulunamadı: {marker}"
        )

version_match = re.search(
    r"^version:\s*(\d+)\.(\d+)\.(\d+)\+(\d+)\s*$",
    pubspec,
    flags=re.MULTILINE,
)

if version_match is None:
    raise SystemExit("pubspec.yaml sürüm satırı okunamadı.")

major, minor, patch, build = map(int, version_match.groups())

if (major, minor) != (1, 22):
    raise SystemExit(
        "Bu paket 1.22.x sürümü için hazırlandı.\n"
        f"Depodaki sürüm: {major}.{minor}.{patch}+{build}"
    )

new_version = f"1.23.0+{build + 1}"
backup = Path(tempfile.mkdtemp(prefix="bilgi_rotasi_modes_"))
committed = False

try:
    shutil.copy2(MAIN, backup / "main.dart")
    shutil.copy2(PUBSPEC, backup / "pubspec.yaml")

    TARGET.write_bytes(base64.b64decode(SOURCE_B64))

    main = main.replace(
        "part 'gameplay_boost.dart';",
        "part 'gameplay_boost.dart';\npart 'quick_modes.dart';",
        1,
    )

    home_marker = (
        "                const GameplayBoostSettingsButton(),\n"
        "                const SizedBox(height: 18),\n"
        "                FutureBuilder<SavedGame?>("
    )

    if home_marker not in main:
        raise RuntimeError("Ana menü düğmesi ekleme noktası bulunamadı.")

    main = main.replace(
        home_marker,
        "                const GameplayBoostSettingsButton(),\n"
        "                const SizedBox(height: 10),\n"
        "                QuickModesHomeButton(\n"
        "                  questionBank: widget.questionBank,\n"
        "                ),\n"
        "                const SizedBox(height: 18),\n"
        "                FutureBuilder<SavedGame?>(",
        1,
    )

    main, count = re.subn(
        r"Bilgi Rotası • Sürüm 1\.22",
        "Bilgi Rotası • Sürüm 1.23",
        main,
        count=1,
    )
    if count != 1:
        raise RuntimeError("Ana menü sürüm yazısı güncellenemedi.")

    pubspec = re.sub(
        r"^version:\s*.*$",
        f"version: {new_version}",
        pubspec,
        count=1,
        flags=re.MULTILINE,
    )

    MAIN.write_text(main, encoding="utf-8")
    PUBSPEC.write_text(pubspec, encoding="utf-8")

    checks = {
        MAIN: [
            "part 'quick_modes.dart';",
            "QuickModesHomeButton(",
            "Bilgi Rotası • Sürüm 1.23",
        ],
        TARGET: [
            "class QuickModesHubScreen",
            "class SurvivalModeScreen",
            "class SpeedModeScreen",
            "class CategoryDuelGameScreen",
        ],
        PUBSPEC: [f"version: {new_version}"],
    }

    for path, markers in checks.items():
        text = path.read_text(encoding="utf-8")
        for marker in markers:
            if marker not in text:
                raise RuntimeError(
                    f"Kurulum doğrulaması başarısız: {path} / {marker}"
                )

    if shutil.which("dart"):
        run(["dart", "format", "lib/main.dart", "lib/quick_modes.dart"])

    run(["git", "diff", "--check"])

    if shutil.which("flutter"):
        run(["flutter", "analyze", "--no-fatal-infos"])

    run([
        "git", "add",
        "lib/main.dart",
        "lib/quick_modes.dart",
        "pubspec.yaml",
    ])

    changed = subprocess.run(
        ["git", "diff", "--cached", "--quiet"],
        check=False,
    ).returncode != 0

    if not changed:
        raise RuntimeError("Commit edilecek değişiklik bulunamadı.")

    run([
        "git", "commit", "-m",
        "Hayatta Kalma 60 Saniye ve Kategori Duellosu",
    ])
    committed = True
    run(["git", "push", "origin", "main"])

except Exception as error:
    if not committed:
        shutil.copy2(backup / "main.dart", MAIN)
        shutil.copy2(backup / "pubspec.yaml", PUBSPEC)
        if TARGET.exists():
            TARGET.unlink()
        subprocess.run([
            "git", "reset", "--",
            "lib/main.dart", "lib/quick_modes.dart", "pubspec.yaml",
        ], check=False)

    print("\n❌ Kurulum tamamlanamadı.")
    print(str(error))
    if committed:
        print("Commit oluştu. Göndermek için: git push origin main")
    else:
        print("Dosyalar önceki hâline otomatik döndürüldü.")
    raise SystemExit(1)

finally:
    shutil.rmtree(backup, ignore_errors=True)

print("\n✅ Hayatta Kalma modu eklendi.")
print("✅ 60 Saniye modu eklendi.")
print("✅ Kategori Düellosu eklendi.")
print("✅ Yerel rekor sistemi eklendi.")
print("✅ Cevaplar XP ve istatistik sistemine bağlandı.")
print("✅ Hayatta Kalma ve Düello joker/risk sistemine bağlandı.")
print("✅ questions.json dosyasına dokunulmadı.")
print(f"✅ Yeni sürüm: {new_version}")
print("✅ Değişiklikler GitHub main dalına gönderildi.")
